@startuml
class NewsOverview {
  news: List<News>
  nextPageLink: FernUniInternalLink
  previousPageLink: FernUniInternalLink
}

class News {
  date: Date
  headline: Headline
  sections: List<String>
}

class Section {
  text: String
  links: List<FernUniInternalLink>
}

class Headline {
  text: String
  link: FernUniInternalLink
}

' Relationships based on attributes and multiplicities in the original diagram.
' The arrowheads are open arrows to represent navigability/association direction from source class attribute pointing to target type.

NewsOverview "1" --> "0..n" News : 
News "1" --* "1" Headline : >headline
News "1" --o "0..n" Section : 

@enduml
